<script>
  let { state = 'closed', open = false, viewport = 390, dispatch = () => {} } = $props();
  let shown = open || state === 'open';
  const popup = 'flex origin-(--transform-origin) flex-col rounded-lg bg-kumo-base px-4 py-3 text-sm text-kumo-default shadow-lg shadow-kumo-tip-shadow outline outline-kumo-fill transition-[transform,scale,opacity] duration-150 data-starting-style:scale-90 data-starting-style:opacity-0 data-ending-style:scale-90 data-ending-style:opacity-0 data-instant:duration-0 kumo-popover-popup';
  function toggle() { shown = !shown; dispatch('click'); }
</script>
